package com.example.oidcclient.model;

import java.io.Serializable;
import java.time.Instant;
import java.util.Collections;
import java.util.Map;
import java.util.Set;

public class UserSession implements Serializable {

    private static final long serialVersionUID = 1L;

    private String subject;
    private String email;
    private String name;
    private String preferredUsername;
    private Set<String> roles;
    private Map<String, Object> claims;
    private Instant authenticatedAt;
    private Instant tokenExpiresAt;
    private String sessionId;

    public UserSession() {
        this.authenticatedAt = Instant.now();
    }

    // Builder pattern
    public static Builder builder() {
        return new Builder();
    }

    public static class Builder {
        private final UserSession session = new UserSession();

        public Builder subject(String subject) {
            session.subject = subject;
            return this;
        }

        public Builder email(String email) {
            session.email = email;
            return this;
        }

        public Builder name(String name) {
            session.name = name;
            return this;
        }

        public Builder preferredUsername(String preferredUsername) {
            session.preferredUsername = preferredUsername;
            return this;
        }

        public Builder roles(Set<String> roles) {
            session.roles = roles != null ? Collections.unmodifiableSet(roles) : Collections.emptySet();
            return this;
        }

        public Builder claims(Map<String, Object> claims) {
            session.claims = claims != null ? Collections.unmodifiableMap(claims) : Collections.emptyMap();
            return this;
        }

        public Builder tokenExpiresAt(Instant tokenExpiresAt) {
            session.tokenExpiresAt = tokenExpiresAt;
            return this;
        }

        public Builder sessionId(String sessionId) {
            session.sessionId = sessionId;
            return this;
        }

        public UserSession build() {
            return session;
        }
    }

    // Getters
    public String getSubject() { return subject; }
    public String getEmail() { return email; }
    public String getName() { return name; }
    public String getPreferredUsername() { return preferredUsername; }
    public Set<String> getRoles() { return roles; }
    public Map<String, Object> getClaims() { return claims; }
    public Instant getAuthenticatedAt() { return authenticatedAt; }
    public Instant getTokenExpiresAt() { return tokenExpiresAt; }
    public String getSessionId() { return sessionId; }

    public boolean isTokenExpired() {
        return tokenExpiresAt != null && Instant.now().isAfter(tokenExpiresAt);
    }

    @Override
    public String toString() {
        return "UserSession{" +
            "subject='" + subject + '\'' +
            ", email='" + email + '\'' +
            ", name='" + name + '\'' +
            ", authenticatedAt=" + authenticatedAt +
            '}';
    }
}

