package com.example.oidcclient.service;

import com.example.oidcclient.config.OidcProviderProperties;
import com.nimbusds.jose.JWSAlgorithm;
import com.nimbusds.jose.jwk.source.JWKSource;
import com.nimbusds.jose.jwk.source.RemoteJWKSet;
import com.nimbusds.jose.proc.JWSKeySelector;
import com.nimbusds.jose.proc.JWSVerificationKeySelector;
import com.nimbusds.jose.proc.SecurityContext;
import com.nimbusds.jwt.JWTClaimsSet;
import com.nimbusds.jwt.proc.ConfigurableJWTProcessor;
import com.nimbusds.jwt.proc.DefaultJWTClaimsVerifier;
import com.nimbusds.jwt.proc.DefaultJWTProcessor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import jakarta.annotation.PostConstruct;
import java.net.URI;
import java.net.URL;
import java.util.*;

@Service
public class TokenService {

    private static final Logger logger = LoggerFactory.getLogger(TokenService.class);

    private final OidcProviderProperties oidcProperties;
    private final RestTemplate restTemplate;
    private ConfigurableJWTProcessor<SecurityContext> jwtProcessor;

    public TokenService(OidcProviderProperties oidcProperties) {
        this.oidcProperties = oidcProperties;
        this.restTemplate = new RestTemplate();
    }

    @PostConstruct
    public void init() {
        try {
            jwtProcessor = new DefaultJWTProcessor<>();

            JWKSource<SecurityContext> keySource = new RemoteJWKSet<>(
                new URL(oidcProperties.getJwkSetUri())
            );

            JWSAlgorithm expectedAlgorithm = JWSAlgorithm.RS256;
            JWSKeySelector<SecurityContext> keySelector = new JWSVerificationKeySelector<>(
                expectedAlgorithm, keySource
            );

            jwtProcessor.setJWSKeySelector(keySelector);

            // Configure claims verification
            Set<String> requiredClaims = new HashSet<>(Arrays.asList("sub", "iss", "exp", "aud", "iat"));
            jwtProcessor.setJWTClaimsSetVerifier(new DefaultJWTClaimsVerifier<>(
                new JWTClaimsSet.Builder()
                    .issuer(oidcProperties.getIssuer())
                    .build(),
                requiredClaims
            ));

            logger.info("JWT processor initialized successfully");
        } catch (Exception e) {
            logger.error("Failed to initialize JWT processor", e);
            throw new RuntimeException("Failed to initialize JWT processor", e);
        }
    }

    /**
     * Exchange authorization code for tokens at the token endpoint.
     * Uses client_secret_post authentication method.
     */
    public Map<String, Object> exchangeAuthorizationCode(String authorizationCode, String state, String codeVerifier) {
        logger.info("Exchanging authorization code for tokens");

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(Collections.singletonList(MediaType.APPLICATION_JSON));

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "authorization_code");
        body.add("code", authorizationCode);
        body.add("redirect_uri", oidcProperties.getRedirectUri());
        body.add("client_id", oidcProperties.getClientId());
        body.add("client_secret", oidcProperties.getClientSecret());

        // PKCE support
        if (codeVerifier != null && !codeVerifier.isEmpty()) {
            body.add("code_verifier", codeVerifier);
        }

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                URI.create(oidcProperties.getTokenUri()),
                HttpMethod.POST,
                request,
                Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully exchanged authorization code for tokens");
                return response.getBody();
            } else {
                logger.error("Token exchange failed with status: {}", response.getStatusCode());
                throw new RuntimeException("Token exchange failed");
            }
        } catch (Exception e) {
            logger.error("Error during token exchange", e);
            throw new RuntimeException("Failed to exchange authorization code", e);
        }
    }

    /**
     * Validate and parse ID token claims.
     */
    public JWTClaimsSet validateAndParseIdToken(String idToken) {
        try {
            JWTClaimsSet claimsSet = jwtProcessor.process(idToken, null);

            // Additional validation: check audience contains our client_id
            List<String> audience = claimsSet.getAudience();
            if (!audience.contains(oidcProperties.getClientId())) {
                throw new SecurityException("ID token audience does not contain expected client_id");
            }

            // Validate nonce if present (should match the one sent in auth request)
            // This would be checked against session-stored nonce in production

            // Validate authorized party (azp) if present
            String azp = (String) claimsSet.getClaim("azp");
            if (azp != null && !azp.equals(oidcProperties.getClientId())) {
                throw new SecurityException("ID token azp does not match client_id");
            }

            logger.info("ID token validated successfully for subject: {}", claimsSet.getSubject());
            return claimsSet;
        } catch (Exception e) {
            logger.error("ID token validation failed", e);
            throw new RuntimeException("Invalid ID token", e);
        }
    }

    /**
     * Fetch user info from the UserInfo endpoint.
     */
    public Map<String, Object> fetchUserInfo(String accessToken) {
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        headers.setAccept(Collections.singletonList(MediaType.APPLICATION_JSON));

        HttpEntity<Void> request = new HttpEntity<>(headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                URI.create(oidcProperties.getUserInfoUri()),
                HttpMethod.GET,
                request,
                Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                return response.getBody();
            }
            throw new RuntimeException("UserInfo request failed");
        } catch (Exception e) {
            logger.error("Error fetching user info", e);
            throw new RuntimeException("Failed to fetch user info", e);
        }
    }

    /**
     * Refresh access token using refresh token.
     */
    public Map<String, Object> refreshToken(String refreshToken) {
        logger.info("Refreshing access token");

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "refresh_token");
        body.add("refresh_token", refreshToken);
        body.add("client_id", oidcProperties.getClientId());
        body.add("client_secret", oidcProperties.getClientSecret());

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                URI.create(oidcProperties.getTokenUri()),
                HttpMethod.POST,
                request,
                Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Token refreshed successfully");
                return response.getBody();
            }
            throw new RuntimeException("Token refresh failed");
        } catch (Exception e) {
            logger.error("Error refreshing token", e);
            throw new RuntimeException("Failed to refresh token", e);
        }
    }
}

