package com.example.oidcclient.service;

import com.example.oidcclient.model.UserSession;
import com.nimbusds.jwt.JWTClaimsSet;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import jakarta.servlet.http.HttpSession;
import java.time.Instant;
import java.util.*;

@Service
public class UserSessionService {

    private static final Logger logger = LoggerFactory.getLogger(UserSessionService.class);
    private static final String USER_SESSION_ATTRIBUTE = "USER_SESSION";

    /**
     * Create a UserSession from ID token claims.
     */
    public UserSession createSessionFromIdTokenClaims(JWTClaimsSet claims, HttpSession httpSession) {
        try {
            String subject = claims.getSubject();
            String email = (String) claims.getClaim("email");
            String name = (String) claims.getClaim("name");
            String preferredUsername = (String) claims.getClaim("preferred_username");

            // Extract roles from claims (common patterns)
            Set<String> roles = extractRoles(claims);

            Instant expiresAt = claims.getExpirationTime() != null
                ? claims.getExpirationTime().toInstant()
                : null;

            UserSession userSession = UserSession.builder()
                .subject(subject)
                .email(email)
                .name(name)
                .preferredUsername(preferredUsername)
                .roles(roles)
                .claims(claims.getClaims())
                .tokenExpiresAt(expiresAt)
                .sessionId(httpSession.getId())
                .build();

            // Store in HTTP session
            httpSession.setAttribute(USER_SESSION_ATTRIBUTE, userSession);

            // Set session timeout (30 minutes)
            httpSession.setMaxInactiveInterval(1800);

            logger.info("Created user session for subject: {}", subject);
            return userSession;
        } catch (Exception e) {
            logger.error("Failed to create user session from ID token claims", e);
            throw new RuntimeException("Failed to create user session", e);
        }
    }

    /**
     * Create a UserSession from Spring Security's OidcUser.
     */
    public UserSession createSessionFromOidcUser(OidcUser oidcUser, HttpSession httpSession) {
        String subject = oidcUser.getSubject();
        String email = oidcUser.getEmail();
        String name = oidcUser.getFullName();
        String preferredUsername = oidcUser.getPreferredUsername();

        Set<String> roles = new HashSet<>();
        oidcUser.getAuthorities().forEach(auth -> roles.add(auth.getAuthority()));

        Instant expiresAt = oidcUser.getIdToken().getExpiresAt();

        UserSession userSession = UserSession.builder()
            .subject(subject)
            .email(email)
            .name(name)
            .preferredUsername(preferredUsername)
            .roles(roles)
            .claims(oidcUser.getIdToken().getClaims())
            .tokenExpiresAt(expiresAt)
            .sessionId(httpSession.getId())
            .build();

        httpSession.setAttribute(USER_SESSION_ATTRIBUTE, userSession);
        httpSession.setMaxInactiveInterval(1800);

        logger.info("Created user session for subject: {} (from OidcUser)", subject);
        return userSession;
    }

    /**
     * Get the current user session from HTTP session.
     */
    public Optional<UserSession> getCurrentSession(HttpSession httpSession) {
        UserSession session = (UserSession) httpSession.getAttribute(USER_SESSION_ATTRIBUTE);
        if (session != null && !session.isTokenExpired()) {
            return Optional.of(session);
        }
        if (session != null && session.isTokenExpired()) {
            logger.warn("User session token expired for subject: {}", session.getSubject());
            invalidateSession(httpSession);
        }
        return Optional.empty();
    }

    /**
     * Invalidate the current session.
     */
    public void invalidateSession(HttpSession httpSession) {
        httpSession.removeAttribute(USER_SESSION_ATTRIBUTE);
        httpSession.invalidate();
        logger.info("User session invalidated");
    }

    /**
     * Extract roles from JWT claims (supports common claim structures).
     */
    @SuppressWarnings("unchecked")
    private Set<String> extractRoles(JWTClaimsSet claims) {
        Set<String> roles = new HashSet<>();

        try {
            // Check for "roles" claim
            Object rolesClaim = claims.getClaim("roles");
            if (rolesClaim instanceof List) {
                ((List<String>) rolesClaim).forEach(roles::add);
            }

            // Check for realm_access.roles (Keycloak pattern)
            Object realmAccess = claims.getClaim("realm_access");
            if (realmAccess instanceof Map) {
                Object realmRoles = ((Map<String, Object>) realmAccess).get("roles");
                if (realmRoles instanceof List) {
                    ((List<String>) realmRoles).forEach(roles::add);
                }
            }

            // Check for resource_access (Keycloak pattern)
            Object resourceAccess = claims.getClaim("resource_access");
            if (resourceAccess instanceof Map) {
                ((Map<String, Object>) resourceAccess).forEach((key, value) -> {
                    if (value instanceof Map) {
                        Object clientRoles = ((Map<String, Object>) value).get("roles");
                        if (clientRoles instanceof List) {
                            ((List<String>) clientRoles).forEach(role ->
                                roles.add(key + ":" + role));
                        }
                    }
                });
            }

            // Check for groups claim
            Object groupsClaim = claims.getClaim("groups");
            if (groupsClaim instanceof List) {
                ((List<String>) groupsClaim).forEach(group ->
                    roles.add("GROUP_" + group));
            }
        } catch (Exception e) {
            logger.warn("Error extracting roles from claims", e);
        }

        return roles;
    }
}

