package com.example.oidcclient.controller;

import com.example.oidcclient.config.OidcProviderProperties;
import com.example.oidcclient.model.UserSession;
import com.example.oidcclient.service.PkceService;
import com.example.oidcclient.service.TokenService;
import com.example.oidcclient.service.UserSessionService;
import com.nimbusds.jwt.JWTClaimsSet;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.util.UriComponentsBuilder;

import jakarta.servlet.http.HttpSession;
import java.util.Map;
import java.util.Optional;

@Controller
public class AuthController {

    private static final Logger logger = LoggerFactory.getLogger(AuthController.class);

    private static final String SESSION_STATE_KEY = "OIDC_STATE";
    private static final String SESSION_NONCE_KEY = "OIDC_NONCE";
    private static final String SESSION_CODE_VERIFIER_KEY = "OIDC_CODE_VERIFIER";

    private final OidcProviderProperties oidcProperties;
    private final TokenService tokenService;
    private final UserSessionService userSessionService;
    private final PkceService pkceService;

    public AuthController(OidcProviderProperties oidcProperties,
                          TokenService tokenService,
                          UserSessionService userSessionService,
                          PkceService pkceService) {
        this.oidcProperties = oidcProperties;
        this.tokenService = tokenService;
        this.userSessionService = userSessionService;
        this.pkceService = pkceService;
    }

    @GetMapping("/")
    public String home(Model model, HttpSession session) {
        Optional<UserSession> userSession = userSessionService.getCurrentSession(session);
        userSession.ifPresent(s -> model.addAttribute("user", s));
        return "home";
    }

    @GetMapping("/login")
    public String login() {
        return "login";
    }

    /**
     * Initiate the OIDC authorization code flow with PKCE.
     */
    @GetMapping("/auth/authorize")
    public String authorize(HttpSession session) {
        // Generate PKCE parameters
        String codeVerifier = pkceService.generateCodeVerifier();
        String codeChallenge = pkceService.generateCodeChallenge(codeVerifier);
        String state = pkceService.generateState();
        String nonce = pkceService.generateNonce();

        // Store in session for later validation
        session.setAttribute(SESSION_STATE_KEY, state);
        session.setAttribute(SESSION_NONCE_KEY, nonce);
        session.setAttribute(SESSION_CODE_VERIFIER_KEY, codeVerifier);

        String authorizationUrl = UriComponentsBuilder
            .fromUriString(oidcProperties.getAuthorizationUri())
            .queryParam("response_type", "code")
            .queryParam("client_id", oidcProperties.getClientId())
            .queryParam("redirect_uri", oidcProperties.getRedirectUri())
            .queryParam("scope", oidcProperties.getScopes())
            .queryParam("state", state)
            .queryParam("nonce", nonce)
            .queryParam("code_challenge", codeChallenge)
            .queryParam("code_challenge_method", "S256")
            .build()
            .toUriString();

        logger.info("Redirecting to authorization endpoint");
        return "redirect:" + authorizationUrl;
    }

    /**
     * Handle the OIDC callback with authorization code.
     */
    @GetMapping("/auth/callback")
    public String callback(
            @RequestParam(value = "code", required = false) String code,
            @RequestParam(value = "state", required = false) String state,
            @RequestParam(value = "error", required = false) String error,
            @RequestParam(value = "error_description", required = false) String errorDescription,
            HttpSession session,
            Model model) {

        // Handle error response from provider
        if (error != null) {
            logger.error("OIDC authorization error: {} - {}", error, errorDescription);
            model.addAttribute("error", "Authentication failed: " + error);
            return "login";
        }

        // Validate state parameter to prevent CSRF
        String storedState = (String) session.getAttribute(SESSION_STATE_KEY);
        if (storedState == null || !storedState.equals(state)) {
            logger.error("State parameter mismatch - possible CSRF attack");
            model.addAttribute("error", "Invalid state parameter");
            return "login";
        }

        // Clean up state from session
        session.removeAttribute(SESSION_STATE_KEY);

        if (code == null || code.isEmpty()) {
            logger.error("No authorization code received");
            model.addAttribute("error", "No authorization code received");
            return "login";
        }

        try {
            // Retrieve code verifier for PKCE
            String codeVerifier = (String) session.getAttribute(SESSION_CODE_VERIFIER_KEY);
            session.removeAttribute(SESSION_CODE_VERIFIER_KEY);

            // Exchange authorization code for tokens
            Map<String, Object> tokenResponse = tokenService.exchangeAuthorizationCode(code, state, codeVerifier);

            String idToken = (String) tokenResponse.get("id_token");
            String accessToken = (String) tokenResponse.get("access_token");

            if (idToken == null) {
                throw new RuntimeException("No ID token in response");
            }

            // Validate and parse ID token
            JWTClaimsSet claims = tokenService.validateAndParseIdToken(idToken);

            // Validate nonce
            String storedNonce = (String) session.getAttribute(SESSION_NONCE_KEY);
            session.removeAttribute(SESSION_NONCE_KEY);
            String tokenNonce = (String) claims.getClaim("nonce");
            if (storedNonce != null && !storedNonce.equals(tokenNonce)) {
                logger.error("Nonce mismatch - possible replay attack");
                model.addAttribute("error", "Invalid nonce");
                return "login";
            }

            // Create user session
            UserSession userSession = userSessionService.createSessionFromIdTokenClaims(claims, session);

            // Optionally store tokens securely in session (not in cookies/client-side)
            session.setAttribute("ACCESS_TOKEN", accessToken);
            if (tokenResponse.containsKey("refresh_token")) {
                session.setAttribute("REFRESH_TOKEN", tokenResponse.get("refresh_token"));
            }

            logger.info("User {} authenticated successfully", userSession.getSubject());
            return "redirect:/dashboard";

        } catch (Exception e) {
            logger.error("Authentication failed during token exchange", e);
            model.addAttribute("error", "Authentication failed. Please try again.");
            return "login";
        }
    }

    @GetMapping("/auth/logout")
    public String logout(HttpSession session) {
        userSessionService.invalidateSession(session);

        if (oidcProperties.getEndSessionEndpoint() != null) {
            String logoutUrl = UriComponentsBuilder
                .fromUriString(oidcProperties.getEndSessionEndpoint())
                .queryParam("client_id", oidcProperties.getClientId())
                .queryParam("post_logout_redirect_uri", "http://localhost:8080/")
                .build()
                .toUriString();
            return "redirect:" + logoutUrl;
        }

        return "redirect:/";
    }
}

