// ============================================================
package com.example.oidcclient.exception;

public class OidcAuthenticationException extends RuntimeException {

    private final String errorCode;

    public OidcAuthenticationException(String message) {
        super(message);
        this.errorCode = "OIDC_AUTH_ERROR";
    }

    public OidcAuthenticationException(String message, String errorCode) {
        super(message);
        this.errorCode = errorCode;
    }

    public OidcAuthenticationException(String message, Throwable cause) {
        super(message, cause);
        this.errorCode = "OIDC_AUTH_ERROR";
    }

    public String getErrorCode() {
        return errorCode;
    }
}

// ============================================================
// exception/GlobalExceptionHandler.java
// ============================================================
package com.example.oidcclient.exception;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ExceptionHandler;

@ControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(OidcAuthenticationException.class)
    public String handleOidcAuthException(OidcAuthenticationException ex, Model model) {
        logger.error("OIDC authentication error: {}", ex.getMessage());
        model.addAttribute("error", "Authentication failed. Please try again.");
        return "login";
    }

    @ExceptionHandler(OAuth2AuthenticationException.class)
    public String handleOAuth2Exception(OAuth2AuthenticationException ex, Model model) {
        logger.error("OAuth2 authentication error: {}", ex.getMessage());
        model.addAttribute("error", "Authentication failed. Please try again.");
        return "login";
    }

    @ExceptionHandler(Exception.class)
    public String handleGenericException(Exception ex, Model model) {
        logger.error("Unexpected error", ex);
        model.addAttribute("error", "An unexpected error occurred.");
        return "error";
    }
}